function load(): { s: number; e: number; u: number }[] {
  if (TABLE) return TABLE;
  const out: { s: number; e: number; u: number }[] = [];
  for (const tri of PACKED.split(" ")) {
    const p = tri.split(",");
    const s = parseInt(p[0]!, 36);
    const len = parseInt(p[1]!, 36);
    const u = parseInt(p[2]!, 36);
    out.push({ s, e: s + len - 1, u });
  }
  TABLE = out; // ranges are emitted in ascending startCID order (binary-searchable)
  return out;
}

/** Adobe-Korea1 CID → Unicode code point. undefined if unmapped. */
export function cidToUnicodeKorea1(cid: number): number | undefined {
  if (!Number.isFinite(cid) || cid < 0) return undefined; // NaN/음수 방어(이진탐색이 NaN 에 오동작 방지)
  const t = load();
  let lo = 0;
  let hi = t.length - 1;
  while (lo <= hi) {
    const mid = (lo + hi) >> 1;
    const r = t[mid]!;
    if (cid < r.s) hi = mid - 1;
    else if (cid > r.e) lo = mid + 1;
    else return r.u + (cid - r.s);
  }
  return undefined;
}
